// Obtener respuesta de DeepSeek
const aiData = $input.first().json;
const aiResponse = aiData.choices[0].message.content;

// Obtener datos anteriores
const preparedData = $('Prepare Prompt').first().json;
const sessionId = preparedData.sessionId;

// Función para detectar temas y extraer fuentes
function extractSources(response) {
  const sources = [];
  const lower = response.toLowerCase();

  // CRM
  if (lower.includes('crm') || lower.includes('apollo') || 
      lower.includes('enriquecimiento') || lower.includes('contactos')) {
    sources.push({
      title: '🎯 Eskadia Core - CRM Inteligente',
      url: 'https://eskadia.ai/crm'
    });
  }

  // Flow
  if (lower.includes('flow') || lower.includes('consultoría') || 
      lower.includes('automatización') || lower.includes('implementación') ||
      lower.includes('integración')) {
    sources.push({
      title: '⚙️ Eskadia Flow - Automatización',
      url: 'https://eskadia.ai/flow'
    });
  }

  // Academy
  if (lower.includes('academy') || lower.includes('curso') || 
      lower.includes('formación') || lower.includes('certificación') ||
      lower.includes('aprender') || lower.includes('n8n')) {
    sources.push({
      title: '🎓 Eskadia Academy - Cursos',
      url: 'https://eskadia.ai/academy'
    });
  }

  // Pricing
  if (lower.includes('precio') || lower.includes('plan') || 
      lower.includes('gratis') || lower.includes('free') ||
      lower.includes('$') || lower.includes('costo') ||
      lower.includes('pro') || lower.includes('enterprise')) {
    sources.push({
      title: '💰 Planes y Precios',
      url: 'https://eskadia.ai/pricing'
    });
  }

  // Eliminar duplicados
  return [...new Map(sources.map(s => [s.url, s])).values()].slice(0, 3);
}

const sources = extractSources(aiResponse);

return {
  json: {
    response: aiResponse,
    sources: sources,
    sessionId: sessionId,
    timestamp: new Date().toISOString(),
    metadata: {
      model: aiData.model,
      tokensUsed: aiData.usage?.total_tokens || 0,
      tokensPrompt: aiData.usage?.prompt_tokens || 0,
      tokensCompletion: aiData.usage?.completion_tokens || 0
    }
  }
};

// Error handling
const sessionId = $('Prepare Prompt').first()?.json?.sessionId || 'error-session';

return {
  json: {
    response: 'Lo siento, estoy teniendo problemas técnicos en este momento. 😔 Por favor, intenta de nuevo en unos segundos o contáctanos directamente.',
    sources: [
      {
        title: '📧 Contacto Eskadia',
        url: 'https://eskadia.ai/contact'
      },
      {
        title: '❓ FAQs',
        url: 'https://eskadia.ai/pricing#faq'
      }
    ],
    sessionId: sessionId,
    timestamp: new Date().toISOString(),
    error: true
  }
};
